const SUPABASE_URL = 'https://faklxfakgzkpkbxfihzh.supabase.co';
const SUPABASE_API_KEY = 'REDACTED_SUPABASE_KEY';
const trigger = $('workflow_trigger').first().json;
const userId = trigger.user_id || '';
let recipient_email = trigger.recipient_email;
let bcc_email = trigger.bcc_email;
try {
  const rows = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/app_config_v2?key=in.(recipient_email,bcc_email)&select=key,value&user_id=eq.${encodeURIComponent(userId)}`,
    headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
  });
  for (const row of rows) {
    if (row.key === 'recipient_email' && !recipient_email) recipient_email = row.value;
    if (row.key === 'bcc_email' && !bcc_email) bcc_email = row.value;
  }
} catch (e) {
  if (!recipient_email) recipient_email = 'eric@agileadtesting.com';
}
return [{ json: { SUPABASE_URL, SUPABASE_API_KEY, userId, recipient_email, bcc_email: bcc_email || '', page_size: trigger.page_size || '6x9', project_title: trigger.project_title || '', user_prompt: trigger.user_prompt || '' } }];

let docx;
try { docx = require('docx'); } catch (e) {
  return [{ json: { error: true, filename: '', result: 'The "docx" npm package is not available. Add "docx" to NODE_FUNCTION_ALLOW_EXTERNAL in n8n env settings and run: npm install docx in your n8n directory.' } }];
}
const { Document, Packer, Paragraph, TextRun, HeadingLevel, SectionType, AlignmentType } = docx;
const settings = $('settings').first().json;
const SB = settings.SUPABASE_URL;
const AK = settings.SUPABASE_API_KEY;
const hd = { 'apikey': AK, 'Authorization': 'Bearer ' + AK };
const uf = settings.userId ? '&user_id=eq.' + encodeURIComponent(settings.userId) : '';

// 1. Fetch project
const pr = await this.helpers.httpRequest({ method: 'GET', url: SB + '/rest/v1/writing_projects_v2?title=ilike.*' + encodeURIComponent(settings.project_title) + '*&select=id,title,genre_slug&limit=1' + uf, headers: hd });
const project = Array.isArray(pr) && pr.length > 0 ? pr[0] : null;
if (!project) return [{ json: { error: true, filename: '', result: 'Project not found: ' + settings.project_title } }];

// 2. Fetch all chapters (including prologue=0 and epilogue=999), ordered by chapter_number
let chapters = await this.helpers.httpRequest({ method: 'GET', url: SB + '/rest/v1/published_content_v2?project_id=eq.' + project.id + '&content_type=eq.chapter&order=chapter_number.asc&select=id,title,chapter_number,content_text,storage_path' + uf, headers: hd });
chapters = Array.isArray(chapters) ? chapters : [];
// Fallback: search by genre_slug if no chapters found by project_id
if (chapters.length === 0 && project.genre_slug) {
  const fb = await this.helpers.httpRequest({ method: 'GET', url: SB + '/rest/v1/published_content_v2?content_type=eq.chapter&genre_slug=eq.' + encodeURIComponent(project.genre_slug) + '&order=chapter_number.asc&select=id,title,chapter_number,content_text,storage_path&limit=100' + uf, headers: hd });
  chapters = Array.isArray(fb) ? fb : [];
}
if (chapters.length === 0) return [{ json: { error: true, filename: '', result: 'No chapters found for "' + project.title + '". Write some chapters first.' } }];

// 3. Fetch content from storage for chapters without content_text
for (const c of chapters) {
  if (!c.content_text && c.storage_path) {
    try {
      const raw = await this.helpers.httpRequest({ method: 'GET', url: SB + '/storage/v1/object/' + c.storage_path, headers: hd });
      c.content_text = typeof raw === 'string' ? raw : JSON.stringify(raw);
    } catch (e) { c.content_text = ''; }
  }
}

// 4. Page sizes in twips (1 inch = 1440 twips)
const PS = {
  '5x8':{w:7200,h:11520},'5.06x7.81':{w:7286,h:11246},'5.25x8':{w:7560,h:11520},
  '5.5x8.5':{w:7920,h:12240},'6x9':{w:8640,h:12960},'6.14x9.21':{w:8842,h:13262},
  '6.69x9.61':{w:9634,h:13838},'7x10':{w:10080,h:14400},'7.44x9.69':{w:10714,h:13954},
  '7.5x9.25':{w:10800,h:13320},'8x10':{w:11520,h:14400},'8.25x11':{w:11880,h:15840},
  '8.25x6':{w:11880,h:8640},'8.25x8.25':{w:11880,h:11880},'8.27x11.69':{w:11909,h:16834},
  '8.5x11':{w:12240,h:15840},'8.5x8.5':{w:12240,h:12240}
};
const rawSz = (settings.page_size || '6x9').replace(/[\s\u00d7]/g, '').replace(/by/gi, 'x').toLowerCase();
const dm = PS[rawSz] || PS['6x9'];
const sz = rawSz in PS ? rawSz : '6x9';
const mg = { top: 1080, bottom: 720, left: 1080, right: 720 };

// 5. HTML helpers
function dec(t) {
  return t.replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&quot;/g,'"')
    .replace(/&#39;/g,"'").replace(/&mdash;/g,'\u2014').replace(/&ndash;/g,'\u2013')
    .replace(/&ldquo;/g,'\u201C').replace(/&rdquo;/g,'\u201D').replace(/&lsquo;/g,'\u2018')
    .replace(/&rsquo;/g,'\u2019').replace(/&hellip;/g,'\u2026').replace(/&nbsp;/g,' ')
    .replace(/&#(\d+);/g, function(m, c) { return String.fromCharCode(parseInt(c)); });
}

function pInline(html) {
  const runs = [];
  const parts = html.split(/(<\/?(?:strong|b|em|i)>)/gi);
  let bo = false, it = false;
  for (const p of parts) {
    const l = p.toLowerCase();
    if (l === '<strong>' || l === '<b>') { bo = true; continue; }
    if (l === '</strong>' || l === '</b>') { bo = false; continue; }
    if (l === '<em>' || l === '<i>') { it = true; continue; }
    if (l === '</em>' || l === '</i>') { it = false; continue; }
    const cl = dec(p.replace(/<[^>]+>/g, ''));
    if (cl) {
      const o = { text: cl, font: 'Garamond', size: 24 };
      if (bo) o.bold = true;
      if (it) o.italics = true;
      runs.push(new TextRun(o));
    }
  }
  return runs.length ? runs : [new TextRun({ text: '', font: 'Garamond', size: 24 })];
}

function h2p(html) {
  if (!html) return [new Paragraph({ children: [new TextRun({ text: '', font: 'Garamond', size: 24 })] })];
  const pa = [];
  const re = /<(h[1-6]|p|blockquote|li)[^>]*>([\s\S]*?)<\/\1>|<hr\s*\/?>/gi;
  let m;
  const bl = [];
  while ((m = re.exec(html)) !== null) {
    if (m[0].match(/^<hr/i)) bl.push({ t: 'hr', c: '' });
    else bl.push({ t: m[1].toLowerCase(), c: m[2] || '' });
  }
  if (!bl.length) {
    html.replace(/<[^>]+>/g, '').split(/\n+/).filter(function(l) { return l.trim().length > 0; })
      .forEach(function(l) { bl.push({ t: 'p', c: l.trim() }); });
  }
  for (const b of bl) {
    if (b.t === 'h1') continue;
    if (b.t === 'hr') {
      pa.push(new Paragraph({ children: [new TextRun({ text: '* * *', font: 'Garamond', size: 24 })], alignment: AlignmentType.CENTER, spacing: { before: 360, after: 360 } }));
      continue;
    }
    if (b.t === 'h2') {
      pa.push(new Paragraph({ children: pInline(b.c), heading: HeadingLevel.HEADING_2, spacing: { before: 480, after: 240 } }));
      continue;
    }
    if (b.t === 'h3') {
      pa.push(new Paragraph({ children: pInline(b.c), heading: HeadingLevel.HEADING_3, spacing: { before: 360, after: 180 } }));
      continue;
    }
    if (b.t === 'blockquote') {
      pa.push(new Paragraph({ children: pInline(b.c), indent: { left: 720, right: 720 }, spacing: { before: 120, after: 120 } }));
      continue;
    }
    pa.push(new Paragraph({ children: pInline(b.c), spacing: { after: 120, line: 276 }, indent: { firstLine: 360 } }));
  }
  return pa.length ? pa : [new Paragraph({ children: [new TextRun({ text: '', font: 'Garamond', size: 24 })] })];
}

// 6. Build document
const pp = { size: { width: dm.w, height: dm.h }, margin: mg };

// Title page section
const titleSec = {
  properties: { page: pp },
  children: [
    new Paragraph({ spacing: { before: 4800 } }),
    new Paragraph({
      children: [new TextRun({ text: project.title, font: 'Garamond', size: 56, bold: true })],
      alignment: AlignmentType.CENTER,
      spacing: { after: 1200 }
    })
  ]
};

// Chapter sections — each starts on odd page with Heading 1
const chapSecs = chapters.map(function(c) {
  const cn = parseInt(c.chapter_number);
  const titleLower = (c.title || '').toLowerCase();
  let label;
  if (cn === 0 || titleLower.indexOf('prologue') >= 0) label = c.title || 'Prologue';
  else if (cn === 999 || titleLower.indexOf('epilogue') >= 0) label = c.title || 'Epilogue';
  else label = c.title || ('Chapter ' + cn);

  return {
    properties: { type: SectionType.ODD_PAGE, page: pp },
    children: [
      new Paragraph({ spacing: { before: 2880 } }),
      new Paragraph({
        text: label,
        heading: HeadingLevel.HEADING_1,
        alignment: AlignmentType.CENTER,
        spacing: { after: 720 }
      }),
      ...h2p(c.content_text || '')
    ]
  };
});

const doc = new Document({
  styles: {
    default: { document: { run: { font: 'Garamond', size: 24 } } },
    paragraphStyles: [
      { id: 'Heading1', name: 'Heading 1', basedOn: 'Normal', next: 'Normal',
        run: { font: 'Garamond', size: 36, bold: true },
        paragraph: { alignment: AlignmentType.CENTER } },
      { id: 'Heading2', name: 'Heading 2', basedOn: 'Normal', next: 'Normal',
        run: { font: 'Garamond', size: 28, bold: true } }
    ]
  },
  sections: [titleSec, ...chapSecs]
});

const buf = await Packer.toBuffer(doc);
const safeName = project.title.replace(/[^a-zA-Z0-9 ]/g, '').replace(/\s+/g, '_');
const fn = safeName + '_KDP_' + sz + '.docx';

return [{
  json: {
    error: false,
    filename: fn,
    title: project.title,
    chapters_count: chapters.length,
    page_size: sz,
    result: 'Kindle manuscript created: ' + fn + ' (' + chapters.length + ' chapters, ' + sz + ' trim size)'
  },
  binary: {
    data: await this.helpers.prepareBinaryData(buf, fn, 'application/vnd.openxmlformats-officedocument.wordprocessingml.document')
  }
}];

